local q3 = require(script.Parent.assign)
local rh = require(script.Parent.None)
local rs = require(script.Parent.PropMarkers.Ref)
local pT = require(script.Parent.GlobalConfig).get()
local t4 = { [rs] = rh }
local function t5(iq)
	if pT.typeChecks then
		assert(typeof(iq) == "function", "Expected arg #1 to be a function")
	end
	return function(l2)
		local db = l2[rs]
		local t6 = q3({}, l2, t4)
		return iq(t6, db)
	end
end
return t5
